import{_ as a,M as i,p as l,q as r,R as e,t as n,N as s,a1 as d}from"./framework-e0dd9823.js";const c={},t=e("h1",{id:"node-js-和-npm",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#node-js-和-npm","aria-hidden":"true"},"#"),n(" Node.js 和 NPM")],-1),m={href:"https://npmmirror.com/",target:"_blank",rel:"noopener noreferrer"},p=e("p",null,"Node.js 是能够在服务器端运行 JavaScript 的开放源代码、跨平台执行环境。 它采用 Google 开发的 V8 执行代码，使用事件驱动、非阻塞和异步输入输出模型等技术来提高性能。NPM 是 Node.js 默认的软件包管理系统，一般情况下，我们在安装 Node.js 会默认安装上 NPM。",-1),h={href:"https://nodejs.org/",target:"_blank",rel:"noopener noreferrer"},u=d('<h2 id="node-js-的常用命令" tabindex="-1"><a class="header-anchor" href="#node-js-的常用命令" aria-hidden="true">#</a> Node.js 的常用命令</h2><ol><li><code>node</code>：启动 Node.js，进入交互式命令行模式。</li><li><code>node app.js</code>：运行一个 Node.js 应用程序，其中 <code>app.js</code> 是应用程序的主文件名。</li><li><code>npm</code>：Node.js 的包管理工具，用于安装、更新、卸载、搜索和管理 Node.js 包文件。</li><li><code>npm install package-name</code>：安装一个 Node.js 模块（包）。</li><li><code>npm remove package-name</code>：卸载一个 Node.js 模块（包）。</li><li><code>npm update package-name</code>：更新一个 Node.js 模块（包）。</li><li><code>npm init</code>：创建一个新的 Node.js 应用程序，并生成一个 <code>package.json</code> 文件。</li><li><code>npm start</code>：启动一个 Node.js 应用程序的入口点 <code>server.js</code>。</li><li><code>npm test</code>：运行 Node.js 应用程序的测试脚本。</li><li><code>npm run-script script-name</code>：运行 Node.js 应用程序 <code>package.json</code> 文件中的自定义脚本。</li></ol><h2 id="nvm" tabindex="-1"><a class="header-anchor" href="#nvm" aria-hidden="true">#</a> nvm</h2><p>NVM 是 Node.js 版本管理器的缩写。它使您可以轻松地在同一台计算机上安装和管理多个 Node.js 版本。您可以通过 NVM 随时切换 Node.js 版本，而不会影响系统中其他应用程序的运行。</p>',4),N={href:"https://github.com/coreybutler/nvm-windows/releases",target:"_blank",rel:"noopener noreferrer"},v=d(`<p>常用的 NVM 命令：</p><ol><li><code>nvm install &lt;version&gt;</code>：安装指定版本的 Node.js。例如，nvm install 12.18.2 将安装 Node.js 版本 12.18.2。</li><li><code>nvm use &lt;version&gt;</code>：切换到指定版本的 Node.js。例如，nvm use 12.18.2 将切换到 Node.js 版本 12.18.2。</li><li><code>nvm ls</code>：列出所有已经安装的 Node.js 版本。</li><li><code>nvm current</code>：查看当前正在使用的 Node.js 版本。</li><li><code>nvm alias &lt;name&gt; &lt;version&gt;</code>：为特定版本的 Node.js 创建别名。例如，nvm alias default 12.18.2 将为 Node.js 版本 12.18.2 创建别名&quot;default&quot;，以便以后可以通过 nvm use default 命令轻松切换到这个版本。</li><li><code>nvm uninstall &lt;version&gt;</code>：删除指定版本的 Node.js。</li><li><code>nvm version</code>：查看 NVM 的版本号。</li></ol><h2 id="修改-npm-源" tabindex="-1"><a class="header-anchor" href="#修改-npm-源" aria-hidden="true">#</a> 修改 NPM 源</h2><p>NPM 的默认源为官方源，对于国内用户来说，下载速度可能较慢。可以切换为国内的源来加快下载速度。</p><ol><li>查看当前使用的地址</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> config get registry
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>使用阿里源</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> config <span class="token builtin class-name">set</span> registry https://registry.npmmirror.com/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>恢复官方源</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> config <span class="token builtin class-name">set</span> registry https://registry.npmjs.org/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="nrm" tabindex="-1"><a class="header-anchor" href="#nrm" aria-hidden="true">#</a> nrm</h3><p>nrm 是一个 Node.js 的包管理工具，用于切换和管理不同的 NPM 注册源。nrm 可以帮助我们切换到国内的源，提高下载速度。</p><p>可以用命令直接安装 nrm <code>npm install -g nrm</code></p><p>常用的 nrm 命令：</p><ol><li><code>nrm ls</code>：列出可用的 NPM 源列表。</li><li><code>nrm use registry-name</code>：切换到指定的 NPM 源。</li><li><code>nrm add registry-name registry-url</code>：添加一个新的 NPM 源。</li><li><code>nrm del registry-name</code>：删除指定的 NPM 源。</li><li><code>nrm test registry-name</code>：测试指定 NPM 源的响应时间。</li><li><code>nrm current</code>：显示当前正在使用的 NPM 源。</li></ol>`,15);function g(j,_){const o=i("ExternalLinkIcon");return l(),r("div",null,[t,e("p",null,[n("阿里镜像站地址: "),e("a",m,[n("https://npmmirror.com"),s(o)])]),p,e("p",null,[e("a",h,[n("Node.js 下载地址"),s(o)])]),u,e("p",null,[e("a",N,[n("NVM Windows 下载地址 "),s(o)])]),v])}const f=a(c,[["render",g],["__file","node-nvm-nrm.html.vue"]]);export{f as default};
